CREATE PROC [dbo].[CREATE_B2CL] @FromDate datetime, @ToDate datetime AS DECLARE @GSTIN AS CHAR(16) DECLARE @HSNCODETablename AS CHAR(16) DECLARE @HSNCodeField AS CHAR(12) DECLARE @IMTableQry AS VARCHAR(500) DECLARE @CompStateName As VarChar(50) SET @HSNCODETablename='##HSNCODETABLE' IF OBJECT_ID('tempdb..' + @HSNCODETablename) IS NOT NULL  EXEC ('DROP TABLE ' + @HSNCODETablename) SELECT @CompStateName=txt FROM SysParam Where paramCode='StateName' IF OBJECT_ID('dbo.B2CL','U') IS NOT NULL DROP TABLE B2CL IF OBJECT_ID('dbo.B2CL_Info','U') IS NOT NULL DROP TABLE B2CL_Info SELECT @HSNCodeField=Txt FROM SysParam WHERE ParamCode='AnalysisCodeUsedToStoreHSNCode' SET @IMTableQry= 'SELECT StockNo,'+ @HSNCodeField +' AS HSNCODE INTO ' + @HSNCODETablename + ' FROM ItemMaster' EXEC (@IMTableQry) SELECT @GSTIN=Txt FROM SysParam WHERE ParamCode='LocalSTaxRegnNo' SELECT  STD.DocNoPrefix + '/' + CONVERT(VARCHAR(6),STD.DocNo) AS 'Invoice Number', STD.DocDt AS 'Invoice date', CAST(SUM(STD.DocEntNetValue) AS Decimal(10,2)) AS 'Invoice Value', (CASE WHEN ISNULL(CUST.LSTNo,'')='' OR LEN(CUST.LSTNo)<5 THEN (SELECT Code FROM Genlookup WHERE REcID=92 AND Descr=ML.State) ELSE LEFT(CUST.LSTNo,2) END) AS 'Place Of Supply', CAST(STD.stdTaxComp1Per+STD.stdTaxComp2Per AS Decimal(10,2))  AS 'Rate', CAST(SUM(STD.Taxav1) AS Decimal(10,2)) AS 'Taxable Value', CAST(SUM((CASE WHEN ML.State=@CompStateName THEN STD.TaxComp3 ELSE '' END)) AS Decimal(10,2))  AS 'CESS Amount', '' AS 'E-Commerce GSTIN' INTO B2CL FROM StktrnDtls STD INNER JOIN StkTrnHdr STH ON STD.DocNoPrefix=STH.DocNoPrefix AND STD.DocNo=STH.DocNo AND STD.TrnType=STH.TrnType INNER JOIN (SELECT LSTNo, Code,MailListSrlNo,NM,'2100' as RecType FROM Customers UNION ALL SELECT LSTNo, Code,MailListSrlNo,NM, '2200' as RecType FROM ChainStores)AS CUST ON CUST.Code=STH.PartyId  AND CUST.RecType=STH.TrnType INNER JOIN MailingList ML ON CUST.MailListSrlNo=ML.RecNo WHERE (STH.TrnType=2100 OR STH.TrnType=2200) AND (LEN(CUST.LSTNO)<5 OR ISNULL(CUST.LSTNO,'')='') AND STH.NetDocvalue>250000 AND STD.DocDt>=@FromDate AND STD.DocDt<=@ToDate AND STD.DocDt>=(SELECT dt FROM SYSPARAM WHERE ParamCode='GSTImplementationDate') AND STD.CustTaxtype <> '0' GROUP BY ML.State, CUST.NM, STD.DocNoPrefix, STD.DocNo, STD.DocDt, CUST.LSTNO, STD.stdTaxComp1Per, STD.stdTaxComp2Per, STD.stdTaxComp3Per UPDATE  CD set [Place of Supply] = Cast([Place of Supply] as Varchar(4)) + '-' + GL.Descr  FROM B2CL CD Inner JOIN (SELECT Code,DEscr FROM GenLookUp WHERE RecID=92 ) GL on CD.[Place of Supply] = GL.Code SELECT COUNT(DISTINCT [Invoice Number]) AS [No. Of Invoices],SUM([Invoice Value]) AS [Total Inv value],SUM([Taxable Value]) AS [Total Taxable value],SUM([CESS AMOUNT]) AS [Total Cess] INTO B2CL_Info FROM B2CL IF OBJECT_ID('B2CL_Header','U') IS NULL CREATE TABLE B2CL_Header ( [Summary For B2CL(5)] Char(1) ) INSERT INTO InfoTable Values('B2CL',2,'<<Default>>','B2CL',2) 